import { Component, Element, Event, EventEmitter, h, Host, Prop } from '@stencil/core';
import { MonthHeaderVariant } from '../wdpr-month-header/wdpr-month-header';
import { CalendarMode, CalendarSize } from '../wdpr-calendar.model';
import { customTwMerge } from '../../../utils/utils';

@Component({
  tag: 'wdpr-single-calendar',
  shadow: true,
  styles: ':host(.full-width) { width: 100%; }',
})
export class WdprSingleCalendar {
  /**
   * Reference to host element.
   * @type {HTMLWdprSingleCalendarElement}
   */
  @Element() el: HTMLWdprSingleCalendarElement;

  /**
   * The variant of the month header.
   * - `default`: shows navigation and title
   * - `minimal`: reduced styling
   *
   * @default "default"
   * @type {"default" | "with-arrows"}
   */
  @Prop() monthHeaderVariant: MonthHeaderVariant = 'default';

  /**
   * The calendar mode.
   * - `single`: user selects one date
   * - `range`: user selects a start and end date
   *
   * @default "single"
   * @type {"single" | "range"}
   */
  @Prop() mode: CalendarMode = 'single';

  /**
   * The calendar Max range in days
   *
   * @default 0
   * @type {Number}
   */
  @Prop() maxRange = 0;
  /**
   * The date currently setting as the Maximum end date in Range mode.
   * Internal use only.
   * @type {Date | null}
   */
  @Prop() maxRangeDate: Date | null = null;
  /**
   * The date that will be used to display the month in the calendar.
   * Default is the current date.
   * @type {Date}
   */
  @Prop() displayDate: Date = new Date();

  /**
   * Selected date.
   * Only used when `mode="single"`.
   * @type {Date | null}
   * @default null
   */
  @Prop() selectedDate: Date | null = null;

  /**
   * The start date of the selected range.
   * Only used when `mode="range"`.
   *
   * @type {Date | null}
   * @default null
   */
  @Prop() startDate: Date | null = null;

  /**
   * The end date of the selected range.
   * Only used when `mode="range"`.
   *
   * @type {Date | null}
   * @default null
   */
  @Prop() endDate: Date | null = null;

  /**
   * Currently hovered date in the calendar.
   * @type {Date | null}
   * @default null
   */
  @Prop() hoverDate: Date | null = null;

  /**
   * Currently focused date in the calendar.
   * @type {Date | null}
   * @default null
   */
  @Prop() focusDate: Date | null = null;

  /**
   * The minimum date formatted.
   * @type {Date | null}
   */
  @Prop() minDate: Date | null = null;

  /**
   * The maximum date formatted.
   * @type {Date | null}
   */
  @Prop() maxDate: Date | null = null;

  /**
   * Whether to always render six weeks in the calendar view.
   * Useful for keeping calendar height consistent.
   *
   * @default false
   * @type {boolean}
   */
  @Prop() enableSixWeeks: boolean = false;

  /**
   * The date format string (uses date-fns format syntax).
   *
   * @default "MM/dd/yyyy"
   * @example "dd-MM-yyyy"
   * @type {string}
   */
  @Prop() format: string = 'MM/dd/yyyy';

  /**
   * The extra info for the date cells
   * @type { Map<string, HTMLElement>}
   */
  @Prop() extras: Map<string, HTMLElement> = new Map();

  /**
   * Flag that shows or hide the calendar borders
   * @default true
   * @type {boolean}
   */
  @Prop() displayBorder: boolean = true;

  @Prop() isReadOnly: boolean = false;

  @Prop() fullWidth?: boolean = false;

  @Prop() isDateBlocked?: (date: Date) => boolean;
  @Prop() isDateDot?: (date: Date) => boolean;
  @Prop() getDatePrice?: (date: Date | string) => number | undefined;

  /**
   * Whether this disabled cells should set a slash in the disabled dates or not.
   * @default false
   */
  @Prop({ reflect: true }) showDisabledSlash: boolean = false;

  /**
   * The calendar size.
   *
   * @default "medium"
   * @type { "xsmall" | "small" | "medium"}
   */
  @Prop({ reflect: true }) size: CalendarSize = 'medium';

  /**
   * Fired when the previous month button is clicked.
   * @event
   * @type {void}
   */
  @Event({ eventName: 'previousMonth' }) previousMonth: EventEmitter<void>;

  /**
   * Fired when the next month button is clicked.
   * @event
   * @type {void}
   */
  @Event({ eventName: 'nextMonth' }) nextMonth: EventEmitter<void>;

  /**
   * Fired when a date is selected (in single mode).
   * Emits an object with the selected date.
   *
   * @event
   * @type {{ date: string }} Object with ISO date string (e.g. { date: "06/19/2025" })
   */
  @Event({ eventName: 'dateSelected' }) dateSelected: EventEmitter<{ date: string }>;

  /**
   * On date hover event.
   * @event
   * @type {{ date: string }}  Object with ISO date string (e.g. { date: "06/19/2025" })
   */
  @Event({ eventName: 'dateHover' }) dateHover: EventEmitter<{ date: string }>;

  /**
   * On focus of date moves out event.
   * @event
   * @type {{ date: string }}  Object with ISO date string (e.g. { date: "06/19/2025" })
   */
  @Event() focusMoveOut: EventEmitter<{ date: string }>;

  private _onPreviousMonth = (event: CustomEvent<void>) => {
    event.stopPropagation();
    this.previousMonth.emit();
  };

  private _onNextMonth = (event: CustomEvent<void>) => {
    event.stopPropagation();
    this.nextMonth.emit();
  };

  private _onFocusMoveOut = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.focusMoveOut.emit(event.detail);
  };

  private _onDateSelected = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.dateSelected.emit(event.detail);
  };

  private _onDateHover = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.dateHover.emit(event.detail);
  };

  private get _wrapperClasses() {
    const widthClass = this.fullWidth ? 'w-full' : wrapperSizeClasses[this.size];

    return customTwMerge(wrapperBaseClasses, widthClass);
  }

  private get _containerClasses() {
    return customTwMerge(containerBaseClasses, this.displayBorder ? containerBorderClasses : null);
  }

  render() {
    return (
      <Host class={{ 'full-width': this.fullWidth }}>
        <div part="calendar" class={this._wrapperClasses}>
          <wdpr-month-header
            id="month-title"
            displayDate={this.displayDate}
            variant={this.monthHeaderVariant}
            minDate={this.minDate}
            maxDate={this.maxDate}
            onNextMonth={this._onNextMonth}
            onPreviousMonth={this._onPreviousMonth}
          />
          <div
            part="calendar-surface"
            class={this._containerClasses}
            role="grid"
            aria-rowcount={this.enableSixWeeks ? '7' : '6'}
            aria-colcount="7"
            aria-label={`${this.displayDate.toLocaleString('default', { month: 'long' })} ${this.displayDate.getFullYear()}`}
          >
            <wdpr-week-header fullWidth={this.fullWidth} />

            <div role="row" aria-hidden="true">
              <wdpr-divider />
            </div>

            <wdpr-month
              mode={this.mode}
              enableSixWeeks={this.enableSixWeeks}
              startDate={this.startDate}
              endDate={this.endDate}
              hoverDate={this.hoverDate}
              focusDate={this.focusDate}
              selectedDate={this.selectedDate}
              displayDate={this.displayDate}
              format={this.format}
              minDate={this.minDate}
              maxDate={this.maxDate}
              extras={this.extras}
              showDisabledSlash={this.showDisabledSlash}
              maxRangeDate={this.maxRangeDate}
              fullWidth={this.fullWidth}
              isReadOnly={this.isReadOnly}
              isDateBlocked={this.isDateBlocked}
              isDateDot={this.isDateDot}
              getDatePrice={this.getDatePrice}
              onFocusMoveOut={this._onFocusMoveOut}
              onDateSelected={this._onDateSelected}
              onDateHover={this._onDateHover}
            />
          </div>
        </div>
      </Host>
    );
  }
}

const wrapperBaseClasses = 'flex flex-col gap-100';

const wrapperSizeClasses: Record<CalendarSize, string> = {
  xsmall: 'w-[272px]',
  small: 'w-[288px]',
  medium: 'w-[288px] md:w-[324px]',
};

const containerBaseClasses = 'flex flex-col gap-100 rounded-150 px-150 pt-150 pb-200 bg-surface-default';
const containerBorderClasses = 'border-solid border-012 border-stroke-neutral-medium';
