import { Component, Element, h, Prop, Event, EventEmitter, State, Watch } from '@stencil/core';
import { getPreviousMonth, getNextMonth, isBeforeDay, isAfterDay, endOfMonth } from '../../../utils/date.utils';

export type MonthHeaderVariant = 'default' | 'with-arrows';

@Component({
  tag: 'wdpr-month-header',
  shadow: true,
})
export class WdprMonthHeader {
  /**
   * Reference to host element.
   * @type {HTMLWdprMonthHeaderElement}
   */
  @Element() el: HTMLWdprMonthHeaderElement;

  @State() private _isPrevMonthDisabled: boolean = false;

  @State() private _isNextMonthDisabled: boolean = false;

  @State() private _month!: string;

  @State() private _year!: string;

  /**
   * The variant of the month header.
   * - `default`: shows title
   * - `with-arrows`: shows navigation and title
   *
   * @default "default"
   * @type {"default" | "with-arrows"}
   */
  @Prop() variant: MonthHeaderVariant = 'default';

  /**
   * The date that will be used to display the month in the calendar.
   * Default is the current date.
   * @type {Date}
   */
  @Prop() displayDate: Date = new Date();

  /**
   * The minimum date formatted.
   * @type {Date | null}
   */
  @Prop() minDate: Date | null = null;

  /**
   * The maximum date formatted.
   * @type {Date | null}
   */
  @Prop() maxDate: Date | null = null;

  /**
   * Fired when the previous month button is clicked.
   * @event
   * @type {void}
   */
  @Event({ eventName: 'previousMonth' }) previousMonthClick: EventEmitter<void>;

  /**
   * Fired when the next month button is clicked.
   * @event
   * @type {void}
   */
  @Event({ eventName: 'nextMonth' }) nextMonthClick: EventEmitter<void>;

  @Watch('displayDate')
  @Watch('minDate')
  @Watch('maxDate')
  validateButtons() {
    const prevMonth = getPreviousMonth(this.displayDate);
    const nextMonth = getNextMonth(this.displayDate);

    const lastDayOfPrevMonth = endOfMonth(prevMonth);
    const firstDayOfNextMonth = nextMonth;

    this._isPrevMonthDisabled = this.minDate && isBeforeDay(lastDayOfPrevMonth, this.minDate);
    this._isNextMonthDisabled = this.maxDate && isAfterDay(firstDayOfNextMonth, this.maxDate);
  }

  @Watch('displayDate')
  setTitle() {
    this._month = this.displayDate.toLocaleString(navigator.language || 'default', { month: 'long' });
    this._year = this.displayDate.toLocaleString(navigator.language || 'default', { year: 'numeric' });
  }

  componentWillLoad() {
    this.validateButtons();
    this.setTitle();
  }

  private onPreviousMonth = () => {
    if (!this._isPrevMonthDisabled) {
      this.previousMonthClick.emit();
    }
  };

  private onNextMonth = () => {
    if (!this._isNextMonthDisabled) {
      this.nextMonthClick.emit();
    }
  };

  render() {
    const withArrows = this.variant === 'with-arrows';

    return (
      <section part="month-header" class="flex items-center py-100 justify-between">
        {withArrows && (
          <wdpr-icon-button variant="primary" iconName="previous" a11yLabel="Previous Month" disabled={this._isPrevMonthDisabled} onClicked={this.onPreviousMonth} />
        )}

        <h2 class="m-0 flex items-center gap-100" aria-live="polite" aria-atomic="true" part="month-header-title">
          <span class="heading-small !text-text-body">{this._month}</span>
          <span class="heading-small-alt !text-text-body">{this._year}</span>
        </h2>

        {withArrows && <wdpr-icon-button variant="primary" iconName="next" a11yLabel="Next Month" disabled={this._isNextMonthDisabled} onClicked={this.onNextMonth} />}
      </section>
    );
  }
}
