import { Component, h, Element, Prop, Event, EventEmitter, Fragment } from '@stencil/core';
import { customTwMerge, twMerge } from '../../../utils/utils';
import { formatDateToString } from '../../../utils/date.utils';
import { KEYBOARD_KEYS } from '../../../models/keycodes.model';
import { CellData } from './wdpr-date.model';

@Component({
  tag: 'wdpr-date',
  shadow: true,
})
export class WdprDate {
  /**
   * @internal Reference to extra cell info container.
   */
  private _extraContainer?: HTMLDivElement;

  /**
   * Reference to host element.
   * @type {HTMLWdprDateElement}
   */
  @Element() el: HTMLWdprDateElement;

  /**
   * Data for this calendar cell.
   * Contains the date and state flags for rendering.
   * @type {CellData | null}
   */
  @Prop() cellData: CellData;

  /**
   * Whether this cell should receive keyboard focus.
   * Used for roving tabindex and keyboard navigation.
   * @default false
   */
  @Prop({ reflect: true }) isFocusable: boolean = false;

  /**
   * The date format string (uses date-fns format syntax).
   * @default "MM/dd/yyyy"
   * @example "dd-MM-yyyy"
   * @type {string}
   */
  @Prop({ reflect: true }) format: string = 'MM/dd/yyyy';

  /**
   * The Extra info for the date cell
   * @type { Map<string, HTMLElement>}
   */
  @Prop() extras: Map<string, HTMLElement>;

  /**
   * Whether this disabled cells should set a slash in the disabled dates or not.
   * @default false
   */
  @Prop({ reflect: true }) showDisabledSlash: boolean = false;

  @Prop() isReadOnly: boolean = false;

  @Prop() fullWidth?: boolean = false;

  /**
   * Fired when a date is selected.
   * Emits an object with the selected date.
   *
   * @event
   * @type {{ date: string }} Object with ISO date string (e.g. { date: "06/19/2025" })
   */
  @Event({ eventName: 'dateSelected' }) dateSelected: EventEmitter<{ date: string }>;

  /**
   * Fired when a date is hovered.
   * @event
   * @type {{ date: string }}  Object with ISO date string (e.g. { date: "06/19/2025" })
   */
  @Event({ eventName: 'dateHover' }) dateHover: EventEmitter<{ date: string }>;

  componentDidRender() {
    if (!this._extraContainer) return;

    this._extraContainer.innerHTML = '';

    const key = this.cellData && formatDateToString(this.cellData.date, this.format);
    const node = key ? this.extras?.get(key) : null;

    if (node) {
      const clone = node.cloneNode(true);
      this._extraContainer.appendChild(clone);
    }
  }

  private _onDateHover = () => {
    if (!this.cellData || this.cellData.disabled || this.isReadOnly) return;

    this.dateHover.emit({ date: formatDateToString(this.cellData.date, this.format) });
  };

  private _onDateClick = () => {
    if (!this.cellData || this.cellData.disabled || this.isReadOnly) return;

    this.dateSelected.emit({ date: formatDateToString(this.cellData.date, this.format) });
  };

  private _onKeyDown = (ev: KeyboardEvent) => {
    if (!this.cellData || this.cellData.disabled || this.isReadOnly) return;

    if (ev.key === KEYBOARD_KEYS.ENTER || ev.key === KEYBOARD_KEYS.SPACE) {
      ev.preventDefault();
      this.dateSelected.emit({ date: formatDateToString(this.cellData.date, this.format) });
    }
  };

  private get _ariaLabel() {
    if (!this.cellData) return;

    const formattedDate = formatDateToString(this.cellData.date, this.format);

    if (this.cellData.selected) {
      return `Selected date: ${formattedDate}`;
    }

    if (this.cellData.isStartDate) {
      return `Start date selected: ${formattedDate}`;
    }

    if (this.cellData.inRange) {
      return `Date in range: ${formattedDate}`;
    }

    if (this.cellData.isEndDate) {
      return `End date selected: ${formattedDate}`;
    }

    return formattedDate;
  }

  private get _wrapperClasses() {
    const baseClasses = 'flex flex-col items-center justify-center';
    if (!this.cellData || !this.fullWidth) return baseClasses;

    const isEnabled = !this.cellData.disabled;

    const range = this.cellData && this.cellData.inRange && isEnabled ? (this.cellData.price ? priceRangeClasses : containerInRangeDateClasses) : null;
    const firstDate = this.cellData && this.cellData.isStartDate && isEnabled ? (this.cellData.price ? firstDatePriceRangeClasses : firstDateRangeClasses) : null;
    const endDate = this.cellData && this.cellData.isEndDate && isEnabled ? (this.cellData.price ? endDatePriceRangeClasses : endDateRangeClasses) : null;

    return customTwMerge(baseClasses, range, firstDate, endDate);
  }

  private get _containerClasses() {
    if (!this.cellData) return customTwMerge(containerBaseClasses);

    const isEnabled = !this.cellData.disabled;

    return customTwMerge(
      containerBaseClasses,
      containerActiveDateClasses,
      this.cellData && this.cellData.inRange && isEnabled ? containerInRangeDateClasses : null,
      this.cellData && this.cellData.isStartDate && isEnabled ? containerStartDateClasses : null,
      this.cellData && this.cellData.isEndDate && isEnabled ? containerEndDateClasses : null,
      this.isFocusable ? 'z-10' : null,
    );
  }

  private get _dateClasses() {
    if (!this.cellData) return customTwMerge(dateBaseClasses);

    if (this.isReadOnly) return customTwMerge(dateBaseClasses, readOnlyDateClasses);

    const isEnabled = !this.cellData.disabled;

    return customTwMerge(
      dateBaseClasses,
      this.cellData && this.cellData.disabled ? disabledDateClasses : activeDateClasses,
      this.cellData && isEnabled && (this.cellData.selected || this.cellData.isStartDate || this.cellData.isEndDate) ? selectedDateClasses : null,
      this.cellData && isEnabled && this.cellData.inRange ? inRangeDateClasses : null,
    );
  }

  get _dotClasses() {
    return twMerge(this.cellData.selected || this.cellData.isStartDate || this.cellData.isEndDate ? 'bg-surface-default' : '');
  }

  render() {
    const key = this.cellData && formatDateToString(this.cellData.date, this.format);
    const safeKey = key && key.replace(/\//g, '-');
    const hasExtra = key && this.extras?.has(key);

    const parsedPrice = this.cellData && typeof this.cellData.price === 'number' && !isNaN(this.cellData.price) ? `$${this.cellData.price}` : null;
    const priceId = this.cellData && this.cellData.price ? `price-desc-${safeKey}` : undefined;

    return (
      <div class={this._wrapperClasses} part="date-cell-wrapper">
        <div
          role="gridcell"
          class={this._containerClasses}
          onClick={this._onDateClick}
          onKeyDown={this._onKeyDown}
          onMouseEnter={this._onDateHover}
          tabIndex={this.isFocusable ? 0 : -1}
          aria-label={this.cellData && this._ariaLabel}
          aria-describedby={[priceId, this.cellData && this.cellData.showDot ? `dot-desc-${safeKey}` : undefined].filter(Boolean).join(' ') || undefined}
          aria-disabled={!this.cellData || this.cellData.disabled ? 'true' : null}
          aria-selected={this.cellData && (this.cellData.selected || this.cellData.isStartDate || this.cellData.isEndDate) ? 'true' : null}
          part="date-cell"
        >
          {this.cellData && (
            <span part="date-label" class={this._dateClasses}>
              {this.cellData.disabled && this.showDisabledSlash && !this.cellData.isOutsideMonth && (
                <span class="absolute left-[10px] top-[10px]">
                  <wdpr-icon-library size="medium" icon="calendar-icon" />
                </span>
              )}

              {this.cellData.date.getDate()}

              {this.cellData.showDot && (
                <Fragment>
                  <div class="absolute bottom-075" part="date-cell-dot">
                    <wdpr-calendar-dot dotStyle={this._dotClasses} />
                  </div>

                  <span id={`dot-desc-${safeKey}`} class="sr-only">
                    This day is marked with an indicator dot.
                  </span>
                </Fragment>
              )}
            </span>
          )}
        </div>
        {this.cellData && this.cellData.price && (
          <span id={priceId} class="label-xsmall text-text-label py-050" part="date-cell-price">
            <span class="sr-only">Price: </span>
            {parsedPrice}
          </span>
        )}
        <div class={customTwMerge(hasExtra ? 'my-050' : '')} ref={el => (this._extraContainer = el)} part="date-cell-extra-info" />
      </div>
    );
  }
}

const containerBaseClasses = 'flex w-full max-w-[42px] max-h-[42px] aspect-square label-large group focus:outline-none';
const containerActiveDateClasses = 'cursor-pointer';
const containerInRangeDateClasses = 'bg-surface-neutral-light';
const containerStartDateClasses = 'rounded-l-pill bg-surface-neutral-light';
const containerEndDateClasses = 'rounded-r-pill bg-surface-neutral-light';

const priceRangeClasses = '[background:linear-gradient(to_bottom,var(--color-surface-neutral-light)_42px,transparent_42px)]';
const firstDatePriceRangeClasses =
  '[background:linear-gradient(to_top,white_18px,transparent_18px),linear-gradient(to_left,var(--color-surface-neutral-light)_50%,transparent_50%)]';
const firstDateRangeClasses = '[background:linear-gradient(to_left,var(--color-surface-neutral-light)_50%,transparent_50%)]';
const endDatePriceRangeClasses =
  '[background:linear-gradient(to_top,white_18px,transparent_18px),linear-gradient(to_right,var(--color-surface-neutral-light)_50%,transparent_50%)]';
const endDateRangeClasses = '[background:linear-gradient(to_right,var(--color-surface-neutral-light)_50%,transparent_50%)]';

const dateBaseClasses =
  'relative flex justify-center items-center w-full h-full rounded-pill group-focus-visible:text-actionable-default-alt group-focus-visible:outline-050 group-focus-visible:outline-stroke-actionable-focused group-focus-visible:outline-solid group-focus-visible:outline-offset-2';
const readOnlyDateClasses = 'cursor-default text-text-neutral-extra-dark';
const disabledDateClasses = 'relative cursor-not-allowed text-text-disabled';
const activeDateClasses = 'text-text-body group-hover:bg-surface-neutral-light';
const inRangeDateClasses = 'group-hover:bg-surface-actionable-alt-hover group-hover:text-white';
const selectedDateClasses = 'bg-surface-actionable-alt-selected text-white group-hover:bg-surface-actionable-alt-hover';
